Hi @dam-ease 
This is a concurrency issue, below is a code sample that should help you reliably reproduce it:
- append a character, wait a second -> exception
- delete a character, wait a second -> exception
```
import 'package:flutter/foundation.dart';
import 'package:flutter/material.dart';
import 'package:flutter/services.dart';

void main() => runApp(const MyApp());

class MyApp extends StatefulWidget {
  const MyApp({super.key});

  @override
  _MyAppState createState() => _MyAppState();
}

class _MyAppState extends State<MyApp> {
  var _key = 1;

  @override
  Widget build(BuildContext context) {
    final spellCheck = kIsWeb
        ? null
        : SpellCheckConfiguration(
            spellCheckService: DelayedSpellCheckService(),
          );
    return MaterialApp(
      home: Scaffold(
        body: Center(
          child: TextFormField(
            key: ValueKey(_key),
            initialValue: "hello",
            spellCheckConfiguration: spellCheck,
            onChanged: (value) {
              setState(() => ++_key);
            },
          ),
        ),
      ),
    );
  }
}

class DelayedSpellCheckService extends SpellCheckService {
  final _delegate = DefaultSpellCheckService();

  @override
  Future<List<SuggestionSpan>?> fetchSpellCheckSuggestions(
    Locale locale,
    String text,
  ) async {
    await Future.delayed(const Duration(seconds: 1));
    return _delegate.fetchSpellCheckSuggestions(locale, text);
  }
}
```

