Hi @vanlooverenkoen 

You can try this ugly workaround with listening FocusNode and calling scroll after some timeout (when keyboard becomes visible and the body height changed).

<details>
 <summary>Code sample</summary>

```
import 'dart:async';

import 'package:flutter/material.dart';

void main() => runApp(MaterialApp(home: ForgotPasswordScreen()));

class ForgotPasswordScreen extends StatefulWidget {
  const ForgotPasswordScreen();

  @override
  State<StatefulWidget> createState() => ForgotPasswordScreenState();
}

class ForgotPasswordScreenState extends State<ForgotPasswordScreen> {
  FocusNode _textFieldFocus;
  final buttonKey = GlobalKey();

  @override
  void initState() {
    _textFieldFocus = FocusNode();
    _textFieldFocus.addListener(_onFocusChange);
    super.initState();
  }

  @override
  void dispose() {
    _textFieldFocus.dispose();
    super.dispose();
  }

  void _onFocusChange() {
    if (_textFieldFocus.hasFocus) {
      Timer(Duration(seconds: 1), () {
        _scrollToBottom();
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(),
      body: GestureDetector(
        onTap: () {
          FocusScope.of(context).requestFocus(new FocusNode());
        },
        child: SafeArea(
          child: ListView(
            children: [
              Center(
                child: Padding(
                  padding: const EdgeInsets.all(34),
                  child: Column(
                    children: [
                      Text(
                        'long textlong textlong textlong textlong textlong textlong textlong textlong textlong textlong textlong textlong textlong textlong text',
                      ),
                      Container(
                        height: 47,
                      ),
                      TextField(
                        autofocus: true,
                        focusNode: _textFieldFocus,
                        decoration: InputDecoration(
                          border: const OutlineInputBorder(),
                        ),
                      ),
                      Container(
                        height: 47,
                      ),
                      MaterialButton(
                        key: buttonKey,
                        color: Colors.deepOrange,
                        child: Text('button'),
                        onPressed: () {},
                      ),
                    ],
                  ),
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }

  _scrollToBottom() async {
    Scrollable.ensureVisible(
      buttonKey.currentContext,
      duration: Duration(milliseconds: 250),
      curve: Curves.easeIn,
    );
  }
}

```

</details>

