So I'm not sure what the right solution is, but it looks like the issue is that on the Samsung keyboard, the backspace comes in as a `KeyMessage` (which is probably what you were talking about with the IME Input API stuff) rather than going through the `TextInputPlugin`.

I did find a workaround for @ueman 's example – wrapping the `FeedbackBottomSheet` with `DefaultTextEditingShortcuts` and `DefaultTextEditingActions` restores the backspace button:

<details>
<summary>main.dart</summary>

```
import 'package:flutter/material.dart';
import 'package:flutter_localizations/flutter_localizations.dart';

void main() {
  WidgetsFlutterBinding.ensureInitialized();
  runApp(Directionality(
    textDirection: TextDirection.ltr,
    child: Localizations(
      delegates: [
        GlobalMaterialLocalizations.delegate,
        GlobalCupertinoLocalizations.delegate,
        GlobalWidgetsLocalizations.delegate,
      ],
      locale: Locale('en'),
      child: MediaQuery(
        data: MediaQueryData.fromWindow(WidgetsBinding.instance!.window),
        child: Stack(children: [
          const MyApp(),
          DefaultTextEditingShortcuts(
            child: DefaultTextEditingActions(
              child: FeedbackBottomSheet(
                child: (context) => StringFeedback(),
              ),
            ),
          ),
        ]),
      ),
    ),
  ));
}

class MyApp extends StatelessWidget {
  const MyApp({Key? key}) : super(key: key);

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Flutter Demo',
      theme: ThemeData(primarySwatch: Colors.blue),
      home: const MyHomePage(title: 'Flutter Demo Home Page'),
