  }
}

class HomePage extends StatefulWidget {
  const HomePage({Key? key}) : super(key: key);

  @override
  State<HomePage> createState() => _HomePageState();
}

class _HomePageState extends State<HomePage> {
  final FocusNode _focusNode = FocusNode();
  final TextEditingController _controller = TextEditingController();
  Color? _color;

  @override
  void initState() {
    super.initState();
    _focusNode.addListener(_onFocusChanged);
  }

  void _onFocusChanged() {
    // Here you can see that the TextField will show the cursor but will lost
    // after setState
    Future.delayed(
        const Duration(seconds: 2),
        () => setState(() {
              print('focus changed: ${_focusNode.hasFocus}');

              _color = _focusNode.hasFocus ? Colors.green[200] : null;

              // No problem after keeping any color
              // _color=_randomColor();
            }));
  }

  Color _randomColor() {
    return Color((math.Random().nextDouble() * 0xFFFFFF).toInt())
        .withOpacity(1);
  }

  @override
  void dispose() {
    _focusNode.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
        body: Container(
            // setState + color = TextField cursor gone
            color: _color,
            child: Center(
                child: SizedBox(
                    width: 150,
                    child: TextField(
                        focusNode: _focusNode, controller: _controller)))));
  }
}
